<title>Build Monitor Dashboard</title>
<style>
/* reset essenziale */
*{box-sizing:border-box;margin:0;padding:0;font-family:system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif}
body{background:#f3f5f7;color:#222;line-height:1.4;padding:1rem}
nav{background:#111;color:#fff;padding:0.8rem 1.2rem;border-radius:8px;display:flex;gap:1.5rem;flex-wrap:wrap;justify-content:space-between;align-items:center}
nav h1{font-weight:600;font-size:1.2rem}
nav ul{display:flex;gap:1rem;list-style:none}
nav li{color:#ccc;cursor:pointer;transition:color 0.2s}
nav li:hover{color:#fff}
.hero{background:#e8e9ea;padding:1.2rem;border-radius:10px;margin-top:1.2rem;display:flex;flex-wrap:wrap;justify-content:space-between;align-items:center}
.hero .stato{font-size:1.5rem;font-weight:600;color:#0a5c0a}
.hero small{color:#555;margin-top:0.2rem}
.filtro{background:#fff;padding:0.8rem;border-radius:8px;margin-top:1.2rem;display:flex;gap:0.8rem;flex-wrap:wrap}
.filtro input{flex:1;min-width:140px;padding:0.6rem;border:1px solid #ccc;border-radius:6px}
.filtro button{background:#0984da;color:#fff;border:none;padding:0.6rem 1.2rem;border-radius:6px;cursor:pointer}
table{width:100%;background:#fff;border-radius:10px;margin-top:1.2rem;overflow:auto;box-shadow:0 1px 4px rgba(0,0,0,0.08)}
thead{background:#fafafa;border-bottom:2px solid #ddd}
th, td{padding:0.8rem 1rem;text-align:left;border-bottom:1px solid #eaeaea}
tr:hover{background:#f9f9f9}
td .job-name{font-weight:500}
td .status-badge{background:#1f8e1f;color:#fff;padding:0.2rem 0.6rem;border-radius:12px;font-size:0.8rem}
